#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int freq[101]={0};
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            freq[x]++;
        }
        int first=1;
        for(int v=1; v<=100; v++){
            while(freq[v]--){
                if(!first) printf(" ");
                printf("%d",v);
                first=0;
            }
        }
        if(T) printf("\n");
    }
    return 0;
}

