import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        freq = [0]*101
        for _ in range(N):
            x = int(next(it))
            freq[x] += 1
        line = []
        for v in range(1,101):
            if freq[v]:
                line.extend([str(v)]*freq[v])
        out_lines.append(' '.join(line))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

